import React, { useState } from 'react';
import { Container, Paper, Typography, TextField, Button, Box, Autocomplete, Popper, ListSubheader } from '@mui/material';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function NewQuestion({ showSnackbar }) {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [tags, setTags] = useState([]);
  const [allTags, setAllTags] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showAllTags, setShowAllTags] = useState(false);
  const navigate = useNavigate();

  React.useEffect(() => {
    // Lấy allTags từ localStorage (Questions đã từng lưu)
    try {
      const questions = JSON.parse(localStorage.getItem('questions')) || [];
      const tags = Array.from(new Set(questions.flatMap(q => q.tags || [])));
      setAllTags(tags);
    } catch {
      setAllTags([]);
    }
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post('http://localhost:8080/api/questions', { title, content, tags });
      showSnackbar && showSnackbar('Đã thêm câu hỏi mới!', 'success');
      navigate('/questions');
    } catch (err) {
      showSnackbar && showSnackbar('Thêm câu hỏi thất bại!', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm" sx={{mt:6}}>
      <Paper elevation={3} sx={{p:4}}>
        <Typography variant="h5" gutterBottom>Thêm câu hỏi mới</Typography>
        <Box component="form" onSubmit={handleSubmit} sx={{display:'flex', flexDirection:'column', gap:2}}>
          <TextField label="Tiêu đề" value={title} onChange={e => setTitle(e.target.value)} required fullWidth />
          <TextField label="Nội dung" value={content} onChange={e => setContent(e.target.value)} required fullWidth multiline minRows={4} />
          <Autocomplete
            multiple
            freeSolo
            options={showAllTags ? allTags : allTags.slice(0,7).concat(allTags.length > 7 ? ['__SEE_MORE__'] : [])}
            value={tags}
            onChange={(e, value) => {
              if (value.includes('__SEE_MORE__')) {
                setShowAllTags(true);
                // Loại bỏ option đặc biệt khỏi value
                setTags(tags);
              } else {
                setTags(value);
              }
            }}
            renderOption={(props, option) =>
              option === '__SEE_MORE__' ? (
                <li {...props} style={{fontStyle:'italic', color:'#1976d2', fontWeight:600}}>
                  ... Xem thêm tag
                </li>
              ) : (
                <li {...props}>{option}</li>
              )
            }
            renderInput={(params) => <TextField {...params} label="Chọn hoặc nhập tag (tab)" required />}
            sx={{background:'#fff'}}
          />
          <Button type="submit" variant="contained" color="primary" disabled={loading}>
            {loading ? 'Đang gửi...' : 'Thêm câu hỏi'}
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}
